odata-gateway-012.codeExamples:
" RAP-based OData V4 service creation steps (S/4HANA)
" Step 1: Create CDS Root View Entity
@AbapCatalog.sqlViewName: 'ZV_SALESORDER'
@OData.publish: false
@UI.headerInfo: { typeName: 'Sales Order' }
define root view entity ZR_SalesOrder
  as select from vbak
{
  key vbeln as SalesOrder,
      kunag as Customer,
      netwr as NetAmount,
      erdat as OrderDate
}
" Step 2: Create Behavior Definition (BDEF)
managed implementation in class ZBP_SalesOrder unique;
strict ( 2 );
define behavior for ZR_SalesOrder alias SalesOrder
persistent table vbak
{
  create; update; delete;
  field ( readonly ) SalesOrder;
}
" Step 3: In ADT - Create Service Definition
define service ZSD_SalesOrder {
  expose ZR_SalesOrder as SalesOrder;
}
" Step 4: Create Service Binding (OData V4 UI binding)
" Binding Type: OData V4 - UI
" Service: ZSD_SalesOrder
" Publish -> service URL generated automatically

