" CDS View with Analytics annotations for InA
@AbapCatalog.sqlViewName: 'ZV_SALES_ANALYT'
@Analytics.dataCategory: #FACT
@Analytics.dataExtract.enabled: true
define view ZA_SalesAnalytics
  as select from vbak
{
  @Analytics.measure: { aggFunction: #SUM }
  netwr as NetAmount,
  @Analytics.dimension: true
  vkorg as SalesOrg,
  @Analytics.dimension: true
  erdat as OrderDate
}
" InA endpoint auto-generated - no manual registration needed

" Managed BDEF (SAP handles persistence)
managed implementation in class ZBP_SalesOrder unique;
define behavior for ZR_SalesOrder
persistent table vbak
{ create; update; delete; }

" Unmanaged BDEF (developer handles persistence)
unmanaged implementation in class ZBP_SalesOrderU unique;
define behavior for ZR_SalesOrder
{ create; update; delete; }
" In behavior pool class:
" METHOD create. " Call BAPI here manually
"   CALL FUNCTION 'BAPI_SALESORDER_CREATEFROMDAT2'...
" ENDMETHOD.

